/**
 * Documentation-content tests for the root `README.md`.
 *
 * These are "doc regression" tests: the branch replaced the standalone
 * "Search" `<button>` with an instant, debounced search-as-you-type input
 * (Enter / Escape / in-field clear button / spinner). The README must document
 * that new UX and must NOT still reference the removed button. These tests
 * parse the raw README text from disk (no DOM needed) — mirroring the approach
 * used by `index.html.test.ts` and `app.css.test.ts` for other static assets —
 * so the environment is pinned to `node` to stay fast and side-effect-free.
 *
 * The two contracts under test, matching the prescribed README edits:
 *
 *   1. The "Final End-to-End Verification Checklist" item 13 no longer
 *      references a "Search button" and instead describes the new instant
 *      (debounced, Enter, Esc/clear, spinner) search behavior.
 *
 *   2. A new `## Search` section exists, positioned immediately after
 *      `## Deep Linking` and before `## Running Tests`, and its body explains
 *      the debounced-search / Enter / empty-query / icon+clear / Escape /
 *      spinner behaviors.
 */
import { describe, it, expect } from 'vitest';
import { readFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const README_PATH = resolve(__dirname, '../README.md');
const README = readFileSync(README_PATH, 'utf8');

/* ===========================================================================
 * Parsing helpers
 * ========================================================================= */

/**
 * Zero-based line index of the FIRST line matching a given heading literal
 * (e.g. `## Deep Linking`). Headings are second-level (`## `) and appear on
 * their own line, so an exact `===` comparison against the trimmed line is
 * unambiguous. Returns -1 when the heading is absent.
 */
function headingLineIndex(heading: string): number {
  const lines = README.split(/\r?\n/);
  for (let i = 0; i < lines.length; i++) {
    if (lines[i].trim() === heading) return i;
  }
  return -1;
}

/**
 * The body text of a `## ` section: everything from the line AFTER the given
 * heading up to (but not including) the next `## ` heading. Returns the empty
 * string when the heading is absent. Used to scope the keyword assertions for
 * the `## Search` section so they don't accidentally match content elsewhere
 * (e.g. the checklist's search line or the Deep Linking examples).
 */
function sectionBody(heading: string): string {
  const lines = README.split(/\r?\n/);
  const start = headingLineIndex(heading);
  if (start === -1) return '';
  const parts: string[] = [];
  for (let i = start + 1; i < lines.length; i++) {
    if (/^##\s/.test(lines[i])) break;
    parts.push(lines[i]);
  }
  return parts.join('\n');
}

/** Case-insensitive substring test against the (lowercased) section body. */
function bodyIncludes(body: string, needle: string): boolean {
  return body.toLowerCase().includes(needle.toLowerCase());
}

/** Case-insensitive regex test against the section body. */
function bodyMatches(body: string, re: RegExp): boolean {
  return re.test(body.toLowerCase());
}

/* ===========================================================================
 * Contract 1: checklist item 13 — removed "Search button", new instant UX
 * ========================================================================= */
describe('README checklist item 13 (search)', () => {
  // The exact legacy line that referenced the now-removed standalone button.
  const LEGACY_LINE =
    '13. **Search** — Search input and button filter entries recursively by name.';

  // The exact prescribed replacement line.
  const EXPECTED_LINE =
    '13. **Search** — typing in the search box runs a debounced (200 ms) recursive name search; press Enter to search immediately, press Esc or click the in-field clear (✕) button to reset to the browse view; a spinner shows while results load.';

  it('no longer references the removed standalone "Search button"', () => {
    // The old checklist item described a Search <button> that no longer exists
    // in the UI; a QA reviewer following the checklist must not be sent looking
    // for it.
    expect(README).not.toContain(LEGACY_LINE);
  });

  it('documents the new instant search behavior with the prescribed line', () => {
    expect(README).toContain(EXPECTED_LINE);
  });

  it('mentions the key new behaviors somewhere in the search checklist item', () => {
    // The checklist item is the last line of the README. Pin its salient
    // concepts so a paraphrase that drops a behavior (e.g. the spinner) fails.
    const itemMatch = README.match(/13\.\s+\*\*Search\*\*[^\n]*/);
    expect(itemMatch, 'checklist item 13 must exist').not.toBeNull();
    const item = (itemMatch![0] as string).toLowerCase();

    expect(item).toMatch(/debounc/);
    expect(item).toMatch(/200\s*ms/);
    expect(item).toMatch(/enter/);
    expect(item).toMatch(/\besc\b/);
    expect(item).toMatch(/clear/);
    expect(item).toMatch(/spinner/);
  });

  it('does not describe the search affordance as a "Search button" in item 13', () => {
    // Belt-and-suspenders: even beyond the exact legacy line, the checklist's
    // search item should not re-introduce the "search button" phrasing (the
    // only button now is the in-field clear button, described as a "clear
    // button", not a generic "Search button").
    const itemMatch = README.match(/13\.\s+\*\*Search\*\*[^\n]*/);
    const item = (itemMatch![0] as string).toLowerCase();
    // "search button" specifically must be gone.
    expect(item).not.toMatch(/search\s+button/);
  });
});

/* ===========================================================================
 * Contract 2: a dedicated `## Search` section, correctly placed and complete
 * ========================================================================= */
describe('README `## Search` section', () => {
  const SEARCH_HEADING = '## Search';
  const body = sectionBody(SEARCH_HEADING);

  it('has a `## Search` section heading', () => {
    expect(headingLineIndex(SEARCH_HEADING)).not.toBe(-1);
  });

  it('is positioned immediately after `## Deep Linking`', () => {
    const deep = headingLineIndex('## Deep Linking');
    const search = headingLineIndex(SEARCH_HEADING);
    expect(deep).not.toBe(-1);
    expect(search).not.toBe(-1);
    expect(search).toBeGreaterThan(deep);
  });

  it('is positioned before `## Running Tests`', () => {
    const search = headingLineIndex(SEARCH_HEADING);
    const running = headingLineIndex('## Running Tests');
    expect(search).not.toBe(-1);
    expect(running).not.toBe(-1);
    expect(search).toBeLessThan(running);
  });

  it('is the very next `## ` section after `## Deep Linking`', () => {
    // "immediately AFTER" Deep Linking: no other second-level heading may sit
    // between them.
    const lines = README.split(/\r?\n/);
    const deep = headingLineIndex('## Deep Linking');
    for (let i = deep + 1; i < lines.length; i++) {
      if (/^##\s/.test(lines[i])) {
        expect(lines[i].trim()).toBe(SEARCH_HEADING);
        return;
      }
    }
    throw new Error('no second-level heading found after `## Deep Linking`');
  });

  describe('body documents the search UX', () => {
    // These concept-scoped checks pass only when the section body actually
    // explains each prescribed behavior. They are scoped to `## Search`'s body
    // so matching the Deep Linking examples or the checklist line does not
    // satisfy them.

    it('explains the 200 ms debounce so results update as you type', () => {
      expect(bodyMatches(body, /debounc/), 'should mention debounce').toBe(true);
      expect(bodyMatches(body, /200\s*ms/), 'should mention the 200 ms delay').toBe(true);
      expect(
        bodyMatches(body, /as you type|keystroke|typing/),
        'should tie the debounce to typing',
      ).toBe(true);
    });

    it('explains that Enter submits immediately without waiting for the debounce', () => {
      expect(bodyIncludes(body, 'enter'), 'should mention Enter').toBe(true);
      expect(
        bodyMatches(body, /immediately|right away|without waiting/),
        'should say Enter is immediate',
      ).toBe(true);
    });

    it('explains an empty/whitespace query returns to browse (no API query)', () => {
      expect(bodyIncludes(body, 'browse'), 'should mention the browse view').toBe(true);
      expect(
        bodyMatches(body, /\bempty\b|whitespace|blank/),
        'should mention empty/whitespace query',
      ).toBe(true);
      expect(
        bodyMatches(body, /\bapi\b|no .*query|not .*sent|without .*request/),
        'should state no empty query is sent to the API',
      ).toBe(true);
    });

    it('describes the magnifying-glass icon and clear (✕) button overlaid in the input', () => {
      expect(
        bodyMatches(body, /magnifying|search icon|leading icon/),
        'should mention the magnifying-glass / leading icon',
      ).toBe(true);
      expect(bodyIncludes(body, 'clear'), 'should mention the clear button').toBe(true);
      expect(body.includes('✕'), 'should show the clear (✕) glyph').toBe(true);
    });

    it('states the clear button visibility is CSS-driven and only shown when there is text', () => {
      expect(bodyMatches(body, /css/), 'should mention CSS').toBe(true);
      expect(bodyMatches(body, /\btext\b/), 'should mention text as the visibility trigger').toBe(
        true,
      );
      expect(
        bodyMatches(body, /placeholder|:placeholder-shown|only .*text|appears .*text|when .*text/),
        'should explain the clear button appears only with text',
      ).toBe(true);
    });

    it('explains Escape (and the clear button) clear the search and return to browse', () => {
      expect(bodyMatches(body, /escape|\besc\b/), 'should mention Escape').toBe(true);
      expect(bodyIncludes(body, 'browse'), 'should mention returning to browse').toBe(true);
      expect(bodyIncludes(body, 'clear'), 'should mention clearing the input').toBe(true);
    });

    it('explains Escape is stopped from propagating so it does not close the host dialog', () => {
      expect(
        bodyMatches(body, /propagat|\bstop\b|swallow|consume|dialog/),
        'should mention stopPropagation / not closing the dialog',
      ).toBe(true);
    });

    it('explains a spinner shows in the results area while a search fetch is in flight', () => {
      expect(bodyIncludes(body, 'spinner'), 'should mention the spinner').toBe(true);
      expect(
        bodyMatches(body, /results area|results region|results/),
        'should place the spinner in the results area',
      ).toBe(true);
      expect(
        bodyMatches(body, /in flight|fetch|loading|while .*search/),
        'should tie the spinner to an in-flight fetch',
      ).toBe(true);
    });

    it('explains the spinner is replaced by the results table or an error message on completion', () => {
      expect(bodyMatches(body, /table|results/), 'should mention the results table').toBe(true);
      expect(bodyMatches(body, /error|message/), 'should mention an error message').toBe(true);
    });
  });
});

